example.com {
    @premium cookie premium 1
    classify {tier} {
        derives_from cookie premium
        when @premium -> p
        default       -> f
    }
    cookie_allow premium uid
    cache_key @premium host url {tier}
    cache_key default host url cookie:uid
    cache_ttl default ttl 60s
    header +cache_status X-Cache
}
